                "schema:longitude": 77.7796
              }
            },
            "dataset:locationOfInterestType": "POINT",
            "dataset:granularity": "HOURLY",
            "dataset:dataType": "FORECAST"
          }
        }
      ],
      "consideration": [
        {
          "id": "consideration-pricing",
          "status": {
            "code": "ACTIVE"
          },
          "considerationAttributes": {
            "@context": "https://schema.org/",
            "@type": "PriceSpecification",
            "priceCurrency": "INR",
            "price": "4999.00",
            "priceComponents": [
              {
                "type": "UNIT",
                "value": "4236.44",
                "currency": "INR",
                "description": "Rainwater Probability Maharashtra March 2025 - Parquet export"
              },
              {
                "type": "TAX",
                "value": "762.56",
                "currency": "INR",
                "description": "GST 18%"
              }
            ]
          }
        }
      ],
      "participants": [
        {
          "id": "climate-data-provider-001",
          "descriptor": {
            "name": "Climate Data Provider",
            "shortDesc": "Provider of climate and meteorological data"
          },
          "participantAttributes": {
            "@context": "https://schema.org/",
            "@type": "Organization",
            "role": "SELLER"
          }
        },
        {
          "id": "buyer-hydrology-lab-001",
          "descriptor": {
            "name": "Hydrology Lab, Delhi"
          },
          "participantAttributes": {
            "@context": "https://schema.org/",
            "@type": "Organization",
            "role": "BUYER"
          }
        }
      ],
      "performance": [],
      "settlements": []
    }
  }
}

